var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하, 하하!","JPN":"は、はは！","ENG":"Ha! Haha!","TWN":"呼，呼呼！"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"봤어? 훈련한 보람이 있지?","JPN":"見た？　訓練した甲斐があっただろ？","ENG":"Did you see that? I knew all that training was gonna pay off.","TWN":"看到沒？這就是訓練的成果！"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……시뮬레이션 결과, 뒤를 노리던 용병을 내가 안 막아 줬으면, 도로시는 당했어.","JPN":"……シミュレーションの結果、後ろを狙っていた傭兵をワタシが食い止めなかったら、ドロシーはやられた。","ENG":"...Simulation results show that if I hadn't stopped that mercenary trying to get us in the back, Dorothy, you would have been hurt.","TWN":"……根據模擬結果，要是我沒擋住你身後的傭兵，你恐怕早已中招。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이거 금메달 땄을 때만큼이나 짜릿한데?","JPN":"これ、金メダル獲った時みたいにビリビリするんだけど！","ENG":"This is just as exciting as when I won a gold medal!","TWN":"感覺就跟奪金一樣痛快欸！"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"안 들리는 척하기는.","JPN":"聞こえないふりしてる。","ENG":"I know you can hear me.","TWN":"還裝沒聽到。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이… 무슨…….","JPN":"この……この……！","ENG":"What in the...!","TWN":"嘖…搞什麼……"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"어딜 가려고?","JPN":"どこに行くの？","ENG":"Going somewhere?","TWN":"你想逃去哪？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저리 가지 못해?!","JPN":"近づかないで！！","ENG":"Get away from me!","TWN":"給我滾開！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응. 보채지 않아도 보내줄 거야.","JPN":"うん。せかさなくても行かせてあげるよ。","ENG":"Okay. But you don’t have to fuss. I’m going to let you go.","TWN":"嗯，不用你說，我也不會攔你。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"잠시 기다려.","JPN":"ちょっと待っててね。","ENG":"Just hold on.","TWN":"等我一下。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"꺄악! 뜨겁……","JPN":"きゃあっ！　熱……","ENG":"Kyaah! It’s...","TWN":"啊！好燙……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":" 지 않네?","JPN":"くないわね？","ENG":" not burning?","TWN":"怎麼不會燙？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루! 괜찮아?","JPN":"ルル！　大丈夫？","ENG":"Lulu! Are you okay?","TWN":"露露！你沒事吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"후후. 불꽃을 던지길래 불이라도 내려나 했는데. 그것도 실패한 모양이구나.","JPN":"ふふ。炎を投げるから火でも点けるつもりなのかと思ったら。それも失敗したようね。","ENG":"Hu hu. I thought she was going to burn me. However, it appears that she failed.","TWN":"呵呵，丟個火球過來，我還以為會燒起來呢，看來是失敗的樣子？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"더는 놀아줄 시간이 없을 것 같으니, 다음을 기약하도록 하지.","JPN":"もう遊んであげる時間はなさそうだから、今度またにするわ。","ENG":"I don’t have time to play with you all. So until next time...","TWN":"我沒時間陪你們玩了，下次再會囉～"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"헤론.","JPN":"ヘロン。","ENG":"Heron.","TWN":"海倫。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"으, 응?","JPN":"う、うん？","ENG":"H-huh?","TWN":"嗯？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"이제 넌……","JPN":"これからあなたは……","ENG":"From now on...","TWN":"之後……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"널 갈기갈기 찢기 위해 핏발 세우고 달려드는 괴물과……","JPN":"あなたをずたずたに引き裂こうと血走って襲ってくる化け物や……","ENG":"You'll have nightmares of being chased by a monster that wants to rip you apart...","TWN":"你就會開始做惡夢，在夢裡會有血盆大口的怪物追著你跑……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"온통 들러붙어 조각조각 먹어 치우려는 진득한 어둠에게 쫓기는 악몽을 꿀 거야.","JPN":"全身にまとわりついて、ぼろぼろに食いつくそうとする、ねっとりした闇に追われる悪夢を見るようになるよ。","ENG":"And a bleak darkness attempting to consume you piece by piece.","TWN":"還有永不見光明的黑暗會吞噬你。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이를 어쩌나. 별로 무섭지 않은 걸?","JPN":"まあ、どうしよう。あんまり怖くないんだけど？","ENG":"Oh my... But that doesn’t sound scary at all!","TWN":"怎麼辦？好像一點都不可怕欸？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"초식 동물이 아무리 매섭게 울어 봤자 초식 동물의 울음소리일 뿐이지. 안 그러니?","JPN":"草食動物がいくら険しく鳴いたところで、草食動物の鳴き声に過ぎないわ。そうでしょう？","ENG":"Doesn’t matter how tough prey looks. It will always be prey in the eyes of the predator...","TWN":"草食動物再怎麼張牙舞爪，始終是吃素的，你說是嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그럼 이건 어때?","JPN":"それじゃあ、これはどう？","ENG":"Then how about this?","TWN":"那這樣呢？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"네가 이룬 모든 것들을 네 손으로 직접 산산조각내는……","JPN":"あなたが成し遂げたすべてを自分の手で粉々にする……","ENG":"Everything you’ve achieved in life... It’ll be destroyed by your hands...","TWN":"你會親手毀掉你努力得來的一切……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그래서 네가 그토록 떨쳐 버리려 애썼던 지긋지긋한 옛날로 돌아가게 되는 그런 악몽을……","JPN":"それで、あれほど吹っ切ろうとした、うんざりするような過去に戻ることになる、そんな悪夢を……","ENG":"And the nightmare will take you back to the past you wish to get away from so bad...","TWN":"然後回到你拼命想擺脫的過去……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"매일 밤. 꾸게 될 거야.","JPN":"毎晩。見るようになるよ。","ENG":"This nightmare... It will come for you every night.","TWN":"你每天晚上都會做這個惡夢。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그, 그 무슨 같잖은 협박을…… 우습지도 않구나.","JPN":"な、なんてくだらない脅し……面白くもないわね。","ENG":"D-do you think your empty threats will work on me?","TWN":"這…這是什麼莫名其妙的威脅……真是荒謬！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤, 헤론이 도망가!","JPN":"へ、ヘロンが逃げる！","ENG":"H-heron is running away!","TWN":"海…海倫跑了！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"괜찮아. 이제 다 괜찮을 거야.","JPN":"大丈夫。もう全部大丈夫だよ。","ENG":"It’s okay. Everything will be all right.","TWN":"沒關係，都沒事了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"금방 다시 잡아올 수 있는데…… 다녀올까?","JPN":"すぐまた捕まえられるけど……行ってこようか？","ENG":"I can drag her back if you want.","TWN":"我應該很快就能追上她……需要我去把她抓回來嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"됐어. 좀비처럼 변한 아이들을 챙기는 게 우선이야.","JPN":"いいよ。ゾンビみたいになった子どもたちが先だ。","ENG":"No. We should take care of the zombie-like children first.","TWN":"不用，先搞定這些像活屍般的孩子吧。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"저 뒤뚱거리는 걸음으로는 동 트고 나서야 헤이븐 귀에 닿을 수 있을 걸.","JPN":"あのふらふらした足どりじゃあ、ヘイブンの耳に入るのは明け方までかかりそうだ。","ENG":"Judging from her wobbly walking, it'll be dawn before Haven learns what happened here.","TWN":"照她的速度，可能要到天亮，事情才會傳到天堂的耳裡。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러고 보니 이 애들은…… 이제 어떡하지?","JPN":"そういえば、この子たちは……どうしようか？","ENG":"But the kids... What do we do?","TWN":"話說回來……孩子們要怎麼辦？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};